// Collapse Data Table load fan-out: Load returns 1 item per store row (returnAll).
// Downstream polling state load may fan-out again; Build uses runOnceForAllItems to emit 1 item.
const loaded = $input.all();
const rowCount = loaded.length;
return [{
  json: {
    store_rows_loaded: rowCount,
    fan_out_collapsed: rowCount > 1,
    test_only: true,
    note: 'Wf47: collapsed shared decisions load fan-out before polling state + build'
  }
}];

// Build getUpdates params from wf47_polling_state_test + derive open IDs from store.
const pollRows = $('Data Table - Load wf47 polling state').all().map((i) => i.json);
const storeRows = $('Data Table - Load shared decisions').all().map((i) => i.json);
const byKey = (k) => {
  const row = pollRows.find((r) => r && r.key === k);
  return row ? row.value : null;
};
const lastUpdateId = Number(byKey('last_update_id') || 0);
const lastHandled = Number(byKey('last_handled_update_id') || 0);
let handledKeys = {};
try {
  const raw = byKey('handled_keys_json') || '{}';
  handledKeys = typeof raw === 'object' ? raw : JSON.parse(String(raw));
} catch {
  handledKeys = {};
}
const openSet = new Set();
for (const r of storeRows) {
  if (r && String(r.status) === 'open' && r.decision_id) {
    openSet.add(String(r.decision_id));
  }
}
const open_decision_ids = [...openSet].sort();
return [{
  json: {
    offset: lastUpdateId,
    limit: 10,
    allowed_updates_json: JSON.stringify(['message', 'callback_query']),
    last_handled_update_id: lastHandled,
    handled_keys: handledKeys,
    open_decision_ids,
    open_decision_ids_source: 'control_plane_decisions_test',
    store_derivation_bypassed: false,
    open_decision_ids_count: open_decision_ids.length,
    state_table: 'wf47_polling_state_test',
    test_only: true
  }
}];

// Normalize Telegram updates while preserving only minimal source metadata for auth + callback ack.
const build = $('Build getUpdates request from state').first().json;
const lastHandled = Number(build.last_handled_update_id || 0);
const resp = $input.item.json;
const body = resp && resp.body !== undefined ? resp.body : resp;
const results = body && Array.isArray(body.result) ? body.result : [];
const OPEN = Array.isArray(build.open_decision_ids) ? build.open_decision_ids : [];
const candidates = [];
for (const u of results) {
  const cq = u && u.callback_query ? u.callback_query : {};
  const msg = (cq && cq.message) ? cq.message : (u && u.message ? u.message : {});
  const text = String(cq.data || msg.text || '').trim();
  let inbound_kind = 'unknown';
  if (text.startsWith('note:')) inbound_kind = 'note';
  else if (text.startsWith('dp:')) inbound_kind = 'callback';
  else if (/^[1-5]$/.test(text)) inbound_kind = 'plain_option';
  const updateId = u && u.update_id !== undefined ? u.update_id : null;
  const sourceChatId = msg && msg.chat && msg.chat.id !== undefined ? msg.chat.id : null;
  const inlineCallbackSource = !!(
    cq &&
    cq.inline_message_id &&
    !(cq.message && cq.message.chat && cq.message.chat.id !== undefined)
  );
  candidates.push({
    update_id: updateId,
    inbound_kind,
    inbound_text: text,
    stale_update_id_guard: updateId != null && updateId <= lastHandled,
    callback_query_id: cq && cq.id ? cq.id : null,
    source_chat_id: sourceChatId,
    inline_callback_source: inlineCallbackSource
  });
}
return {
  json: {
    http_ok: body && body.ok === true,
    result_count: results.length,
    candidates,
    open_decision_ids: OPEN,
    open_decision_ids_source: build.open_decision_ids_source || null,
    store_derivation_bypassed: build.store_derivation_bypassed === true,
    open_decision_ids_count: build.open_decision_ids_count ?? OPEN.length,
    last_handled_update_id: lastHandled,
    handled_keys: build.handled_keys,
    test_only: true
  }
};

// Authorize each candidate against the configured source chat. Fail closed per candidate.
const d = $input.item.json;
const ui = $('Set Wf47 UI config').first().json;
const allowedChatId = String(ui.allowed_chat_id || '').trim();
const configured = allowedChatId.length > 0 && allowedChatId.indexOf('CONFIGURE') === -1 && allowedChatId.indexOf('**') === -1;
const candidates = (d.candidates || []).map((candidate) => {
  let source_chat_authorized = false;
  let auth_block_reason = null;
  if (!configured) {
    auth_block_reason = 'allowed_chat_not_configured';
  } else if (candidate.inline_callback_source === true) {
    auth_block_reason = 'inline_callback_source_unsupported';
  } else if (candidate.source_chat_id === null || candidate.source_chat_id === undefined || String(candidate.source_chat_id).trim() === '') {
    auth_block_reason = 'source_chat_missing';
  } else if (String(candidate.source_chat_id) !== String(allowedChatId)) {
    auth_block_reason = 'source_chat_mismatch';
  } else {
    source_chat_authorized = true;
  }
  return {
    ...candidate,
    source_chat_authorized,
    auth_block_reason
  };
});
return {
  json: {
    ...d,
    candidates,
    allowed_chat_configured: configured,
    block_reason: configured ? (d.block_reason || null) : 'allowed_chat_not_configured'
  }
};

// Multi-update batch: prefer newest authorized+syntactic+non-stale; else stale/dup authorized; else fail-closed.
const d = $input.item.json;
const OPEN = Array.isArray(d.open_decision_ids) ? d.open_decision_ids : [];
const sorted = [...(d.candidates || [])].sort((a, b) => (Number(b.update_id) || 0) - (Number(a.update_id) || 0));
function evaluateCandidate(candidate) {
  const ev = {
    update_id: candidate.update_id,
    inbound_kind: candidate.inbound_kind,
    source_chat_authorized: candidate.source_chat_authorized === true,
    auth_block_reason: candidate.auth_block_reason || null,
    stale_update_id_guard: candidate.stale_update_id_guard === true,
    callback_query_id: candidate.callback_query_id || null,
    syntactic: false,
    decision_id: null,
    selected_option: null,
    note_present: false,
    block_reason: null
  };
  if (candidate.source_chat_authorized !== true) {
    ev.block_reason = candidate.auth_block_reason || 'source_chat_mismatch';
    return ev;
  }
  if (candidate.inbound_kind === 'callback') {
    const m = String(candidate.inbound_text).match(/^dp:(D-\d{4}-[A-Z]):([1-5])$/);
    if (m) {
      ev.syntactic = true;
      ev.decision_id = m[1];
      ev.selected_option = m[2];
      return ev;
    }
    ev.block_reason = 'no_parseable_decision_response';
    return ev;
  }
  if (candidate.inbound_kind === 'plain_option') {
    if (/^[1-5]$/.test(String(candidate.inbound_text))) {
      if (OPEN.length === 1) {
        ev.syntactic = true;
        ev.decision_id = OPEN[0];
        ev.selected_option = String(candidate.inbound_text);
        return ev;
      }
      if (OPEN.length > 1) {
        ev.block_reason = 'ambiguous_plain_option';
        return ev;
      }
    }
    ev.block_reason = 'no_parseable_decision_response';
    return ev;
  }
  if (candidate.inbound_kind === 'note') {
    const nm = String(candidate.inbound_text).match(/^note:(D-\d{4}-[A-Z]):(.+)$/);
    if (nm) {
      ev.syntactic = true;
      ev.decision_id = nm[1];
      ev.note_present = true;
      return ev;
    }
  }
  ev.block_reason = 'no_parseable_decision_response';
  return ev;
}
const evaluated = sorted.map(evaluateCandidate);
let selected = evaluated.find((e) => e.source_chat_authorized && e.syntactic && !e.stale_update_id_guard);
if (!selected) {
  selected = evaluated.find((e) => e.source_chat_authorized && e.syntactic && e.stale_update_id_guard);
}
if (!selected) {
  selected = evaluated.find((e) => e.source_chat_authorized && e.block_reason);
}
if (!selected && evaluated.length) {
  selected = evaluated[0];
}
let parsed = null;
let parse_ok = false;
let block_reason = d.block_reason || 'no_parseable_decision_response';
if (selected) {
  if (selected.syntactic) {
    parsed = {
      update_id: selected.update_id,
      inbound_kind: selected.inbound_kind,
      decision_id: selected.decision_id,
      selected_option: selected.selected_option,
      note_present: selected.note_present,
      callback_query_id: selected.callback_query_id,
      callback_ack_candidate: selected.inbound_kind === 'callback' && !!selected.callback_query_id,
      stale_update_id_guard: selected.stale_update_id_guard
    };
    parse_ok = true;
    block_reason = null;
  } else {
    block_reason = selected.block_reason || selected.auth_block_reason || block_reason;
  }
}
return {
  json: {
    ...d,
    parsed,
    parse_ok,
    block_reason,
    selected_eval: selected || null
  }
};

// Idempotency + auth + callback ack gating using Data Table state (not staticData).
const d = $input.item.json;
const build = $('Build getUpdates request from state').first().json;
const lastHandled = Number(build.last_handled_update_id || 0);
let handledKeys = {};
try {
  const hk = build.handled_keys;
  handledKeys = typeof hk === 'object' && hk ? { ...hk } : JSON.parse(String(hk || '{}'));
} catch {
  handledKeys = {};
}
const p = d.parsed;
let status = 'blocked';
let duplicate_or_stale = false;
let block_reason = d.block_reason || (d.allowed_chat_configured === false ? 'allowed_chat_not_configured' : 'no_matching_update');
let update_id = null;
let decision_id = null;
let selected_option = null;
let note_present = false;
let offset_after = Number(build.offset || 0);
let persist_state = null;
if (d.allowed_chat_configured === false) {
  block_reason = 'allowed_chat_not_configured';
} else if (!p) {
  block_reason = d.block_reason || 'no_parseable_decision_response';
} else {
  update_id = p.update_id;
  decision_id = p.decision_id;
  selected_option = p.selected_option;
  note_present = !!p.note_present;
  const open = (d.open_decision_ids || []).includes(decision_id);
  const slot = selected_option || (note_present ? 'note' : 'unknown');
  const key = decision_id + ':' + slot + ':' + update_id;
  if (update_id != null && update_id <= lastHandled) {
    duplicate_or_stale = true;
    block_reason = 'stale_old_update_id';
  } else if (!open) {
    duplicate_or_stale = true;
    block_reason = 'stale_or_unknown_decision_id';
  } else if (handledKeys[key]) {
    duplicate_or_stale = true;
    block_reason = 'duplicate_or_double_click';
  } else if (p.inbound_kind === 'plain_option' || p.inbound_kind === 'callback') {
    handledKeys[key] = new Date().toISOString();
    offset_after = update_id + 1;
    status = 'accepted';
    block_reason = null;
    persist_state = {
      last_update_id: String(offset_after),
      last_handled_update_id: String(update_id),
      handled_keys_json: JSON.stringify(handledKeys)
    };
  } else if (note_present) {
    status = 'note_placeholder';
    block_reason = null;
  }
}
let callback_ack_applicable = false;
let _callback_query_id_internal = null;
if (
  p &&
  p.callback_ack_candidate === true &&
  p.callback_query_id &&
  (status === 'accepted' || duplicate_or_stale)
) {
  callback_ack_applicable = true;
  _callback_query_id_internal = p.callback_query_id;
}
return {
  json: {
    status,
    decision_id,
    selected_option,
    update_id,
    duplicate_or_stale,
    note_present,
    block_reason,
    allowed_chat_configured: !!d.allowed_chat_configured,
    callback_ack_applicable,
    _callback_query_id_internal,
    offset_after_placeholder: offset_after,
    last_handled_update_id: lastHandled,
    persist_state,
    test_only: true
  }
};

// Emit 3 Data Table upsert rows for accepted path only.
const g = $('Offset dedupe idempotency guard').first().json;
const p = g.persist_state;
if (!p) return [];
const note = 'wf47 polling state TEST ONLY';
return [
  { json: { state_key: 'last_update_id', state_value: p.last_update_id, note } },
  { json: { state_key: 'last_handled_update_id', state_value: p.last_handled_update_id, note } },
  { json: { state_key: 'handled_keys_json', state_value: p.handled_keys_json, note } }
];

// Attach sanitized callback ack result — fail-soft; business classification unchanged.
const base = $('Offset dedupe idempotency guard').item.json;
const resp = $input.item.json;
const body = resp && resp.body !== undefined ? resp.body : resp;
const statusCode = resp && resp.statusCode !== undefined ? resp.statusCode : null;
const httpOk = statusCode >= 200 && statusCode < 300 && body && body.ok === true;
return {
  json: {
    ...base,
    callback_ack_applicable: true,
    callback_ack_attempted: true,
    callback_ack_ok: httpOk,
    callback_ack_block_reason: httpOk ? null : 'ack_api_failure'
  }
};

// Attach callback ack skipped for non-applicable paths.
const d = $input.item.json;
return {
  json: {
    ...d,
    callback_ack_applicable: false,
    callback_ack_attempted: false,
    callback_ack_ok: null,
    callback_ack_block_reason: 'not_applicable'
  }
};

// Deterministic reconvergence: exactly one receipt-side item (fail-closed on unexpected count).
const items = $input.all();
if (items.length !== 1) {
  throw new Error('Merge callback ack branches expected 1 item, got ' + items.length);
}
return [{ json: { ...items[0].json, receipt_items_count: 1 } }];

// Sanitized receipt — no callback_query_id, source_chat_id, token, or raw Telegram body.
const d = $input.item.json;
const build = $('Build getUpdates request from state').first().json;
return {
  json: {
    inspect_status: d.status,
    decision_id: d.decision_id,
    selected_option: d.selected_option,
    update_id: d.update_id,
    duplicate_or_stale: d.duplicate_or_stale,
    note_present: d.note_present,
    block_reason: d.block_reason,
    allowed_chat_configured: d.allowed_chat_configured,
    offset_after_placeholder: d.offset_after_placeholder,
    last_handled_update_id: d.last_handled_update_id,
    callback_ack_applicable: d.callback_ack_applicable === true,
    callback_ack_attempted: d.callback_ack_attempted === true,
    callback_ack_ok: d.callback_ack_attempted ? d.callback_ack_ok === true : null,
    callback_ack_block_reason: d.callback_ack_block_reason ?? (d.callback_ack_applicable ? null : 'not_applicable'),
    open_decision_ids_source: build.open_decision_ids_source || null,
    store_derivation_bypassed: build.store_derivation_bypassed === true,
    open_decision_ids_count: build.open_decision_ids_count ?? null,
    test_only: true
  }
};
